import React, { useState, useMemo, useCallback, useRef } from 'react';
import Header from './components/Header';
import SearchBar from './components/SearchBar';
import FilterDropdown from './components/FilterDropdown';
import SortDropdown from './components/SortDropdown';
import ProductGrid from './components/ProductGrid';
import Footer from './components/Footer';
import productsData from './data/products.json';
import './App.css';

function App() {
  // State management
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [sortOrder, setSortOrder] = useState('default');

  // Refs for scrolling to sections
  const homeRef = useRef(null);
  const shopRef = useRef(null);
  const aboutRef = useRef(null);
  const contactRef = useRef(null);

  // Extract unique categories - memoized to prevent recalculation
  const categories = useMemo(() => {
    const uniqueCategories = [...new Set(productsData.map(p => p.category))];
    return ['All', ...uniqueCategories.sort()];
  }, []);

  // Main filtering and sorting logic - memoized for performance
  const filteredAndSortedProducts = useMemo(() => {
    console.log('🔄 Applying filters and sorting...');

    let result = [...productsData];

    // Search filter
    if (searchTerm.trim()) {
      const searchLower = searchTerm.toLowerCase();
      result = result.filter(product =>
        product.name.toLowerCase().includes(searchLower) ||
        product.category.toLowerCase().includes(searchLower) ||
        product.description.toLowerCase().includes(searchLower)
      );
    }

    // Category filter
    if (selectedCategory !== 'All') {
      result = result.filter(product => 
        product.category === selectedCategory
      );
    }

    // Price sorting
    if (sortOrder === 'asc') {
      result.sort((a, b) => a.price - b.price);
    } else if (sortOrder === 'desc') {
      result.sort((a, b) => b.price - a.price);
    }

    return result;
  }, [searchTerm, selectedCategory, sortOrder]);

  // Callback handlers - memoized to maintain referential stability
  const handleSearchChange = useCallback((term) => {
    setSearchTerm(term);
  }, []);

  const handleCategoryChange = useCallback((category) => {
    setSelectedCategory(category);
  }, []);

  const handleSortChange = useCallback((order) => {
    setSortOrder(order);
  }, []);

  // Scroll to section function
  const scrollToSection = useCallback((ref) => {
    ref.current?.scrollIntoView({ 
      behavior: 'smooth',
      block: 'start'
    });
  }, []);

  return (
    <div className="app">
      <Header 
        onNavigate={(section) => {
          switch(section) {
            case 'home':
              scrollToSection(homeRef);
              break;
            case 'shop':
              scrollToSection(shopRef);
              break;
            case 'about':
              scrollToSection(aboutRef);
              break;
            case 'contact':
              scrollToSection(contactRef);
              break;
            default:
              break;
          }
        }}
      />

      <main className="main-content">
        {/* Home Section */}
        <section ref={homeRef} className="hero-section" id="home">
          <div className="hero-content">
            <h2 className="hero-title">🌸 Discover Beautiful Blooms</h2>
            <p className="hero-subtitle">Fresh flowers delivered straight to your doorstep</p>
            <button 
              className="hero-cta"
              onClick={() => scrollToSection(shopRef)}
            >
              Explore Our Collection
            </button>
          </div>
        </section>

        {/* Shop Section */}
        <section ref={shopRef} className="shop-section" id="shop">
          <div className="container">
            <div className="section-header">
              <h2>🌺 Our Flower Shop</h2>
              <p>Browse our handpicked collection of beautiful blooms</p>
            </div>

            {/* Filters Section */}
            <div className="filters-section">
              <div className="controls-wrapper">
                <SearchBar 
                  searchTerm={searchTerm} 
                  onSearchChange={handleSearchChange} 
                />

                <div className="dropdowns-wrapper">
                  <FilterDropdown 
                    categories={categories}
                    selectedCategory={selectedCategory}
                    onCategoryChange={handleCategoryChange}
                  />

                  <SortDropdown 
                    sortOrder={sortOrder}
                    onSortChange={handleSortChange}
                  />
                </div>
              </div>
            </div>

            {/* Products Section */}
            <div className="products-section">
              <div className="products-header">
                <h3>Our Collection</h3>
                <span className="product-count">
                  {filteredAndSortedProducts.length} {filteredAndSortedProducts.length === 1 ? 'flower' : 'flowers'} found
                </span>
              </div>
              <ProductGrid products={filteredAndSortedProducts} />
            </div>
          </div>
        </section>

        {/* About Section */}
        <section ref={aboutRef} className="about-section" id="about">
          <div className="container">
            <div className="section-header">
              <h2>🌿 About Bloom Haven</h2>
              <p>Our story of bringing beauty to your world</p>
            </div>

            <div className="about-content">
              <div className="about-card">
                <div className="about-icon">🌱</div>
                <h3>Our Story</h3>
                <p>Bloom Haven started in 2020 with a simple mission: to bring fresh, beautiful flowers to everyone's doorstep. What began as a small local shop has blossomed into a beloved online boutique.</p>
              </div>

              <div className="about-card">
                <div className="about-icon">💚</div>
                <h3>Our Values</h3>
                <p>We believe in sustainable sourcing, supporting local growers, and delivering only the freshest blooms. Every bouquet is handcrafted with love and care.</p>
              </div>

              <div className="about-card">
                <div className="about-icon">🌸</div>
                <h3>Quality Promise</h3>
                <p>Every flower that leaves our shop is inspected for quality and freshness. We guarantee your satisfaction with every purchase, or we'll make it right.</p>
              </div>

              <div className="about-card">
                <div className="about-icon">🚚</div>
                <h3>Fast Delivery</h3>
                <p>We offer same-day delivery for orders placed before 2 PM. Your flowers arrive fresh and beautiful, ready to brighten someone's day.</p>
              </div>
            </div>
          </div>
        </section>

        {/* Contact Section */}
        <section ref={contactRef} className="contact-section" id="contact">
          <div className="container">
            <div className="section-header">
              <h2>💌 Get in Touch</h2>
              <p>We'd love to hear from you</p>
            </div>

            <div className="contact-content">
              <div className="contact-info">
                <div className="contact-item">
                  <span className="contact-icon">📍</span>
                  <div>
                    <h4>Visit Us</h4>
                    <p>123 Flower Street, Garden District<br />Portland, OR 97201</p>
                  </div>
                </div>

                <div className="contact-item">
                  <span className="contact-icon">📞</span>
                  <div>
                    <h4>Call Us</h4>
                    <p>(555) 123-4567</p>
                  </div>
                </div>

                <div className="contact-item">
                  <span className="contact-icon">✉️</span>
                  <div>
                    <h4>Email Us</h4>
                    <p>hello@bloomhaven.com</p>
                  </div>
                </div>

                <div className="contact-item">
                  <span className="contact-icon">🕐</span>
                  <div>
                    <h4>Hours</h4>
                    <p>Mon - Fri: 9AM - 7PM<br />Sat - Sun: 10AM - 5PM</p>
                  </div>
                </div>
              </div>

              <form className="contact-form" onSubmit={(e) => e.preventDefault()}>
                <h3>Send us a message</h3>
                <div className="form-group">
                  <label htmlFor="name">Name</label>
                  <input type="text" id="name" placeholder="Your name" required />
                </div>
                <div className="form-group">
                  <label htmlFor="email">Email</label>
                  <input type="email" id="email" placeholder="Your email" required />
                </div>
                <div className="form-group">
                  <label htmlFor="message">Message</label>
                  <textarea id="message" rows="5" placeholder="How can we help you?" required></textarea>
                </div>
                <button type="submit" className="submit-btn">Send Message 🌸</button>
              </form>
            </div>
          </div>
        </section>
      </main>

      <Footer onNavigate={(section) => {
        switch(section) {
          case 'home':
            scrollToSection(homeRef);
            break;
          case 'shop':
            scrollToSection(shopRef);
            break;
          case 'about':
            scrollToSection(aboutRef);
            break;
          case 'contact':
            scrollToSection(contactRef);
            break;
          default:
            break;
        }
      }}/>
    </div>
  );
}

export default App;
